// Aggregate Salesforce sources into fact_channel_daily rows at campaign + region + date grain.
// MQL FIX (15 Jun): include CONVERTED leads. On lead conversion Salesforce rewrites the
// CampaignMember to carry ContactId (LeadId becomes null), so the old `WHERE LeadId != null`
// filter dropped ~574 of 580 MQLs. We now resolve members via LeadId OR ConvertedContactId.
const campaigns = $('SF: Get Campaigns').all().map((i) => i.json);
const opps = $('SF: Get Opportunities').all().map((i) => i.json);
const leads = $('SF: Get Leads').all().map((i) => i.json);
const members = $('SF: Get CampaignMembers').all().map((i) => i.json);

// REGION (15 Jun): resolve off SF Lead.Lead_Region__c (leads) / Opportunity.Account.Region__c (opps),
// fallback to Country/BillingCountry. Real region fields are ~86-99% populated vs dirty Country.
function regionFromField(v) {
  const c = String(v || '').trim().toLowerCase();
  if (['united kingdom','uk','gb','great britain','england','scotland','wales','northern ireland','ireland','ie','guernsey','jersey','isle of man'].includes(c)) return 'UKI';
  if (['belgium','bel','be','luxembourg','lux','lu'].includes(c)) return 'BeLux';
  if (['netherlands','nl','the netherlands','holland'].includes(c)) return 'NL';
  return 'UNASSIGNED';
}

const CHANNEL_BY_TYPE = {
  'Event': 'Events & Webinars',
  'Webinar': 'Events & Webinars',
  'Seminar / Conference': 'Events & Webinars',
  'Email': 'Email',
  'Inbound Web': 'Organic SEO',
  'Content/White Paper': 'Organic SEO',
  // TODO(confirm w/ Margot): paid social vs paid search vs organic social
  'Advertisement': 'LinkedIn Paid',
  'Banner Ads': 'LinkedIn Paid',
  'Social Media': 'LinkedIn Paid',
  // 15 Jun (user-approved): non-marketing-channel / unmapped SF Campaign.Type
  // values route to an explicit 'Other / Unmapped' bucket, NOT Organic SEO.
  'Other': 'Other / Unmapped',
  'Telemarketing': 'Other / Unmapped',
  'Partners': 'Other / Unmapped',
  'Referral Program': 'Other / Unmapped'
};
// CHANNEL FIX (15 Jun): all 14 SF Campaign.Type values mapped; unmapped/non-channel -> 'Other / Unmapped' (never Organic SEO). Paid Search has no SF type (no Google Ads campaigns).
function channelForType(type) { return CHANNEL_BY_TYPE[type] || 'Other / Unmapped'; }

// MQL = 'reached MQL or beyond'. No MQL-date field exists in SF and Lead.Status is a snapshot, so a
// lead that advanced past MQL would vanish from the count (this caused SQL>MQL). We count any status
// that is NOT pre-MQL/disqualified. PROPOSED buckets — confirm w/ Margot (changes a board metric).
const PRE_MQL = new Set(['New','Not Contacted','Nurture','Wrong Contact','Dead-Disqualified','LinkedIn invite sent','LinkedIn contacted']);
function isMql(status) { return !!status && !PRE_MQL.has(status); }
const UNQUALIFIED = ['Unqualified opp']; // 5% stage = not a real SQL

const campaignTypeById = {};
for (const c of campaigns) campaignTypeById[c.Id] = c.Type;

// Lead lookup by Lead.Id AND by ConvertedContactId so converted leads stay attributed.
const leadById = {};
const leadByContactId = {};
for (const l of leads) {
  const v = { status: l.Status, region: l.Lead_Region__c || l.Country };
  leadById[l.Id] = v;
  if (l.ConvertedContactId) leadByContactId[l.ConvertedContactId] = v;
}

const agg = {};
function rowFor(campaignKey, region, date) {
  const key = campaignKey + '|' + region + '|' + date;
  if (!agg[key]) {
    agg[key] = {
      campaign_key: campaignKey, region_code: region,
      channel_name: channelForType(campaignTypeById[campaignKey]),
      pillar_name: '', // TODO: pillar not derivable from Campaign.Type; needs name parse or custom field
      activity_date: date, source: 'salesforce',
      spend: 0, impressions: 0, leads: 0, mql_count: 0,
      sql_count: 0, pipeline_value: 0, closed_won_value: 0, margin_value: 0
    };
  }
  return agg[key];
}

// LEADS + MQL <- CampaignMember joined to Lead (incl. converted leads via ContactId)
for (const m of members) {
  if (!m.CampaignId) continue;
  const date = String(m.CreatedDate || '').slice(0, 10);
  if (!date) continue;
  const lead = (m.LeadId && leadById[m.LeadId]) || (m.ContactId && leadByContactId[m.ContactId]);
  if (!lead) continue; // membership for a pure contact (never a lead) -> not a marketing lead
  const r = rowFor(m.CampaignId, regionFromField(lead.region), date);
  r.leads += 1;
  if (isMql(lead.status)) r.mql_count += 1;
}

// SQL + PIPELINE + CLOSED-WON <- Opportunities
for (const o of opps) {
  if (!o.CampaignId) continue;
  // closed opps dated by CloseDate; open opps by CreatedDate
  const date = String((o.IsClosed ? o.CloseDate : o.CreatedDate) || o.CreatedDate || '').slice(0, 10);
  if (!date) continue;
  const region = o.Account && (o.Account.Region__c || o.Account.BillingCountry);
  const r = rowFor(o.CampaignId, regionFromField(region), date);
  const amount = Number(o.Amount) || 0;
  const qualified = !UNQUALIFIED.includes(o.StageName);
  if (qualified) r.sql_count += 1;                 // every qualified opp = an SQL
  if (o.IsWon) { r.closed_won_value += amount; r.margin_value += amount - (Number(o.Vendor_Cost_Price__c) || 0); } // won revenue + influenced margin (amount - vendor cost)
  else if (qualified && !o.IsClosed) r.pipeline_value += amount; // open qualified pipeline
}

// spend & impressions are NOT in Salesforce -> stay 0 here (filled by T-3: spend sheet / LinkedIn)
return Object.values(agg).map((json) => ({ json }));

const CHANNEL_BY_TYPE = {
  'Event': 'Events & Webinars',
  'Webinar': 'Events & Webinars',
  'Seminar / Conference': 'Events & Webinars',
  'Email': 'Email',
  'Inbound Web': 'Organic SEO',
  'Content/White Paper': 'Organic SEO',
  // TODO(confirm w/ Margot): paid social vs paid search vs organic social
  'Advertisement': 'LinkedIn Paid',
  'Banner Ads': 'LinkedIn Paid',
  'Social Media': 'LinkedIn Paid',
  // 15 Jun (user-approved): non-marketing-channel / unmapped SF Campaign.Type
  // values route to an explicit 'Other / Unmapped' bucket, NOT Organic SEO.
  'Other': 'Other / Unmapped',
  'Telemarketing': 'Other / Unmapped',
  'Partners': 'Other / Unmapped',
  'Referral Program': 'Other / Unmapped'
};
// CHANNEL FIX (15 Jun): all 14 SF Campaign.Type values mapped; unmapped/non-channel -> 'Other / Unmapped' (never Organic SEO). Paid Search has no SF type (no Google Ads campaigns).
function channelForType(type) { return CHANNEL_BY_TYPE[type] || 'Other / Unmapped'; }

// Map Salesforce Campaign records to dim_campaign rows.
return $input.all().map((i) => {
  const c = i.json;
  return { json: {
    campaign_key: c.Id,
    campaign_name: c.Name || null,
    channel_name: channelForType(c.Type),
    source_system: 'salesforce'
  }};
});
